import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class XSSFixedServlet extends HttpServlet {

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Sanitize user input to prevent XSS
        String sanitizedInput = escapeHtml(userInput);

        // Safe code: Sanitized user input is embedded in the HTML response
        String output = "<html><body><h1>Hello, " + sanitizedInput + "</h1></body></html>";

        PrintWriter out = response.getWriter();
        out.println(output);
    }

    private String escapeHtml(String input) {
        if (input == null) {
            return "";
        }
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
